  ('dietitian-moex-03873', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖尿病的Somogyi現象之敘述，下列何者錯誤？', '["屬於在一段時間的低血糖後，卻在早餐前或夜間時，產生反彈性的高血糖現象", "是因為低血糖引發逆調節（counterregulatory）賀爾蒙分泌而導致血糖上升", "可測試清晨3點時的血糖，若血糖值低於70 mg/dL，即是Somogyi現象", "可增加夜間胰島素劑量或減少夜間點心"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03874', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖尿病的併發症胃輕癱（gastroparesis）之營養治療，下列何者錯誤？', '["少量多餐", "降低纖維素攝取", "增加脂肪含量", "以液態食物為佳"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03875', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關降血糖用藥說明之敘述，下列何者錯誤？', '["TZDs可增加周邊胰島素的敏感性", "Repaglinide不屬於磺醯尿素，可刺激胰島素分泌", "Metformin屬雙胍類，可降低肝臟葡萄糖生成", "Acarbose可藉由與α-glucosidase的親和力，促進醣類吸收"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03876', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '曾患有腎結石的病患，為免再次發作，最好的辦法為：', '["喝醋溶解結石", "喝啤酒將結石沖出", "多喝水，最好讓每日排尿量超過2000 c.c", "喝葡萄汁提升抗氧化能力 情況：王太太66歲，身高163 cm，體重60公斤，因呼吸困難，食慾不振，血壓偏高，經門診生化檢驗生化值 如下（括弧內數值為正常值範圍）：BUN 108(7~20)、creatinine 12.6(0.5~1.3)、potassium 6.3(3.5~5.5)、 phosphorus 6.7(2.5~4.8)，醫師診斷後告訴她需要進行透析治療。依此回答下列第20題至第21題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03877', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '若使用CAPD治療，其飲食中每日蛋白質建議量下列何者較適當？', '["0.6~0.8 g/kg", "0.8~1.0 g/kg", "1.0~1.2 g/kg", "1.2~1.5 g/kg"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03878', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王太太在2年後進行腎臟移植，她的飲食在腎臟移植後第一個月（急性期）每日蛋白質攝取建議量為：', '["0.8~1.0 g/kg", "1.0~1.2 g/kg", "1.2~1.3 g/kg", "1.3~1.5 g/kg"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03879', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何種補充品被AHA建議可預防CVD？', '["纖維", "維生素E", "維生素C", "Stanols"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03880', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '末期腎病患者常有副甲狀腺素升高導致骨病變的情形，因此矯正副甲狀腺濃度是一個重要營養治療的目 標，下列何種處置最有效？', '["限制碳酸飲料以減少磷的攝取量", "限制含磷量高的蛋白質食物", "利用利尿劑設法排除鈣", "於疾病初期，盡早補充鈣質"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03881', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關手術患者手術前進食情況的敘述，下列何者錯誤？', '["手術前須禁食24小時", "手術前須讓胃排空，以避免嘔吐造成窒息", "急診開刀進行麻醉前，宜先洗胃", "進行腹腔手術前，應先排空大腸內容物，以避免細菌感染"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03882', 'dietitian', 'dietitian-moex-100-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '動脈粥狀硬化與下列何種生化值無關？', '["血清cholesterol過高", "LDL-C與血清TG過高", "HDL-C過低", "CRP過低"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:03+00:00", "source_pdf_sha1": "fe54146b52d9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
